#nullable enable // autogenerated

using MVZ2Logic.Entities;
using MVZ2Logic.Games;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Level;
using PVZEngine.SeedPacks;

namespace MVZ2Logic.Blueprints
{
    public static class LogicSeedExt
    {
        public static bool CanPick(this SeedPack seed)
        {
            return seed.CanPick(out _);
        }
        public static bool CanPick(this SeedPack seed, out string? errorMessage)
        {
            var id = seed.GetPickError();
            if (NamespaceID.IsValid(id))
            {
                errorMessage = Global.Game.GetBlueprintErrorMessage(id);
                return false;
            }
            errorMessage = null;
            return true;
        }
        public static NamespaceID? GetPickError(this SeedPack seed)
        {
            if (seed == null)
            {
                return LogicBlueprintErrors.invalid;
            }
            else if (seed is ClassicSeedPack)
            {
                if (!seed.IsCharged())
                {
                    return LogicBlueprintErrors.recharging;
                }
                else if (seed.Level.Energy < seed.GetCost())
                {
                    return LogicBlueprintErrors.notEnoughEnergy;
                }
            }
            if (seed.IsDisabled())
            {
                return seed.GetDisableID();
            }
            return null;
        }
        public static bool CanInstantTrigger(this SeedPack seedPack)
        {
            var blueprintDef = seedPack.Definition;
            return blueprintDef.IsTriggerActive() && blueprintDef.CanInstantTrigger();
        }
        public static bool WillInstantEvoke(this SeedPack seedPack)
        {
            var blueprintDef = seedPack.Definition;
            return blueprintDef.WillInstantEvoke(seedPack.Level);
        }
        public static bool WillInstantEvoke(this SeedDefinition definition, LevelEngine level)
        {
            if (definition == null)
                return false;
            if (!definition.CanInstantEvoke())
                return false;
            if (level.IsDay())
            {
                var entityID = definition.GetSeedEntityID();
                if (entityID == null)
                    return false;
                var entityDef = level.Content.GetEntityDefinition(entityID);
                if (entityDef == null || entityDef.IsNocturnal())
                    return false;
            }
            return true;
        }
    }
}
